1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	type Item = { type: string };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	};
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	};
16	
17	const sumBasePremiums = (items: Item[]): number =>
18	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
19	
20	const quotePremium = (step: QuoteStep): number => {
21	  const base = sumBasePremiums(step.items);
22	  const surcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
23	  return Math.ceil(base + surcharge) + PROCESSING_FEE;
24	};
25	
26	export const runScenario = (input: Scenario): unknown => {
27	  const results = input.steps.map((step) => ({ premium: quotePremium(step) }));
28	  return { results };
29	};
